B.XJ=new A.en("\u0628\u0648\u0627\u0628\u062a\u0646\u0627 \u0627\u0644\u0625\u0628\u062f\u0627\u0639\u064a\u0629","Our Creative Gateway","\u0643\u0644 \u0645\u0634\u0631\u0648\u0639 \u0646\u0628\u062f\u0639\u0647 \u064a\u0628\u062f\u0623 \u0645\u0646 \u0647\u0646\u0627. \u0631\u062d\u0644\u0629 \u062a\u0628\u062f\u0623 \u0645\u0646 \u0627\u0644\u0635\u0641\u0631 \u0648\u062a\u0635\u0644 \u0625\u0644\u0649 \u0645\u0627 \u0644\u0627 \u064a\u062a\u0635\u0648\u0631\u0647 \u0623\u062d\u062f.","Every project we create begins here. A journey from zero to the unimaginable.",B.k,B.ad)
B.XQ=new A.en("\u0627\u0644\u0643\u0648\u0646 \u0627\u0644\u0631\u0642\u0645\u064a","The Digital Cosmos","\u0641\u064a \u0639\u0627\u0644\u0645 \u0644\u0627 \u062d\u062f\u0648\u062f \u0644\u0647 \u0645\u0646 \u0627\u0644\u0635\u0641\u0631 \u0648\u0627\u0644\u0623\u062d\u062f\u060c \u0646\u0628\u0646\u064a \u0623\u0643\u0648\u0627\u0646\u0627\u064b \u0631\u0642\u0645\u064a\u0629 \u062a\u062a\u062c\u0627\u0648\u0632 \u062e\u064a\u0627\u0644 \u0627\u0644\u0645\u0628\u062f\u0639\u064a\u0646.","In a world of infinite zeros and ones, we build digital universes beyond imagination.",B.eq,B.jq)
B.XR=new A.en("\u0647\u0646\u062f\u0633\u0629 \u0627\u0644\u0623\u0641\u0643\u0627\u0631","Engineering Ideas","\u0646\u062d\u0648\u0651\u0644 \u0627\u0644\u0623\u0641\u0643\u0627\u0631 \u0627\u0644\u0645\u062c\u0631\u062f\u0629 \u0625\u0644\u0649 \u0647\u064a\u0627\u0643\u0644 \u062a\u0642\u0646\u064a\u0629 \u0635\u0644\u0628\u0629 \u062a\u062a\u062d\u0645\u0644 \u0627\u062e\u062a\u0628\u0627\u0631 \u0627\u0644\u0632\u0645\u0646.","We transform abstract ideas into solid technical structures that stand the test of time.",B.dr,B.np)
B.XF=new A.en("\u0623\u0645\u0648\u0627\u062c \u0627\u0644\u0627\u0628\u062a\u0643\u0627\u0631","Waves of Innovation","\u0645\u062b\u0644 \u0627\u0644\u0623\u0645\u0648\u0627\u062c \u0627\u0644\u062a\u064a \u0644\u0627 \u062a\u062a\u0648\u0642\u0641\u060c \u0646\u0633\u062a\u0645\u0631 \u0641\u064a \u062f\u0641\u0639 \u062d\u062f\u0648\u062f \u0627\u0644\u062a\u0643\u0646\u0648\u0644\u0648\u062c\u064a\u0627 \u0625\u0644\u0649 \u0622\u0641\u0627\u0642 \u062c\u062f\u064a\u062f\u0629.","Like relentless waves, we keep pushing technology boundaries to new horizons.",B.dp,B.mX)
B.XO=new A.en("\u0634\u0628\u0643\u0629 \u0627\u0644\u0635\u0644\u0628\u0629","Solid Networks","\u0634\u0628\u0643\u0627\u062a\u0646\u0627 \u0627\u0644\u062a\u0642\u0646\u064a\u0629 \u0645\u062a\u064a\u0646\u0629 \u0643\u0640\u0627\u0644\u0635\u062e\u0648\u0631. \u0643\u0644 \u062e\u0637 \u0643\u0648\u062f \u0645\u062d\u0633\u0648\u0628\u060c \u0648\u0643\u0644 \u0642\u0631\u0627\u0631 \u0645\u062f\u0631\u0648\u0633.","Our tech networks are solid as rock. Every line of code calculated, every decision deliberate.",B.fX,B.ni)
B.XD=new A.en("\u0639\u0627\u0644\u0645 \u0627\u0644\u062e\u0648\u0627\u0631\u0632\u0645\u064a\u0627\u062a","The Algorithm World","\u0641\u064a \u0623\u0639\u0645\u0627\u0642 \u0627\u0644\u0643\u0648\u062f\u060c \u0646\u0635\u0646\u0639 \u062e\u0648\u0627\u0631\u0632\u0645\u064a\u0627\u062a \u0630\u0643\u064a\u0629 \u062a\u062a\u0639\u0644\u0645 \u0648\u062a\u062a\u0637\u0648\u0631 \u0645\u0639 \u0643\u0644 \u062a\u0641\u0627\u0639\u0644.","In the depths of code, we craft smart algorithms that learn and evolve with every interaction.",B.k,B.ji)
